import type { CollectionEntry } from 'astro:content';
import { randomFromArray } from '~/helpers/random.js';

const categoryIcons = new Map([
	['frameworks', ['integrations/puzzle', 'integrations/grid']],
	['adapters', ['integrations/puzzle', 'integrations/grid', 'integrations/compress']],
	[
		'css+ui',
		[
			'integrations/compress',
			'integrations/grid',
			'integrations/image',
			'integrations/resize-image',
			'integrations/puzzle',
		],
	],
	[
		'performance+seo',
		[
			'integrations/approve-user',
			'approval-check',
			'integrations/compress',
			'integrations/robot',
			'integrations/search-file',
			'integrations/sitemap',
		],
	],
	['analytics', ['approval-check', 'integrations/compress', 'integrations/search-file']],
	['accessibility', ['integrations/approve-user', 'approval-check']],
	['other', ['approval-check', 'integrations/grid', 'integrations/puzzle', 'integrations/sitemap']],
]);

export function iconForIntegration(integration: CollectionEntry<'integrations'>) {
	const icons = integration.data.categories.flatMap(
		(category) => categoryIcons.get(category) ?? [],
	);

	return randomFromArray(icons) ?? 'integrations/puzzle';
}

import type { Hasher } from '../definitions.js';
import type { FontFamily, ResolvedFontFamily } from '../types.js';
import { dedupe, withoutQuotes } from '../utils.js';

export function resolveFamily({
	family,
	hasher,
}: {
	family: FontFamily;
	hasher: Hasher;
}): ResolvedFontFamily {
	// We remove quotes from the name so they can be properly resolved by providers.
	const name = withoutQuotes(family.name);

	return {
		...family,
		name,
		// This will be used in CSS font faces. Quotes are added by the CSS renderer if
		// this value contains a space.
		uniqueName: `${name}-${hasher.hashObject(family)}`,
		weights: family.weights ? dedupe(family.weights.map((weight) => weight.toString())) : undefined,
		styles: family.styles ? dedupe(family.styles) : undefined,
		subsets: family.subsets ? dedupe(family.subsets) : undefined,
		formats: family.formats ? dedupe(family.formats) : undefined,
		fallbacks: family.fallbacks ? dedupe(family.fallbacks) : undefined,
		unicodeRange: family.unicodeRange ? dedupe(family.unicodeRange) : undefined,
	};
}

import kobalte from '@kobalte/tailwindcss';
import typography from '@tailwindcss/typography';
import type { Config } from 'tailwindcss';
import animate from 'tailwindcss-animate';
import colors from 'tailwindcss/colors.js';
import { fontFamily } from 'tailwindcss/defaultTheme.js';
import plugin from 'tailwindcss/plugin.js';

export default {
	content: ['./src/**/*.{astro,js,jsx,ts,tsx}'],
	theme: {
		extend: {
			fontFamily: {
				sans: ['Inter Variable', ...fontFamily.sans],
			},
			colors: {
				theme: {
					base: colors.slate,
				},
			},
		},
	},
	plugins: [
		animate,
		kobalte,
		typography,
		plugin(function customStyles(api) {
			api.addUtilities({
				'.grid-center': {
					display: 'grid',
					'place-items': 'center',
					'place-content': 'center',
				},
			});
		}),
	],
	corePlugins: {
		container: false,
	},
} satisfies Config;
